import type { Updater } from '@tanstack/react-table';
import type { DataTableRowData } from '../../row-data-types.js';
/**
 * Props for row order.
 * @public
 */
export type DataTableRowOrderProps<TData extends DataTableRowData> = DataTableRowOrderControlledProps<TData> | DataTableRowOrderUncontrolledProps<TData>;
/**
 * Options for DataTable row ordering.
 * @public
 */
export interface DataTableRowOrderBaseProps<TData extends DataTableRowData> {
    /**
     * Enables row ordering.
     * @defaultValue false
     */
    rowOrdering?: boolean | {
        /**
         * When enabled, a drag handle is be rendered in the first column for every row.
         */
        enableDragAndDrop?: boolean;
        /**
         * Allows to disable the dragging of certain rows.
         */
        disableRowDragAndDrop?: (row: TData) => boolean;
        /**
         * Locks rows with disabled drag and drop in place if they are sorted to the start or end of the table.
         */
        lockDisabledRows?: boolean | 'start' | 'end';
    };
    /**
     * Callback triggered when row order is changed.
     * @param rowOrder - ordered set of row ids.
     */
    onRowOrderChange?: (rowOrder: string[]) => void;
}
/**
 * Controlled props for row order.
 * @public
 */
export interface DataTableRowOrderControlledProps<TData extends DataTableRowData> extends DataTableRowOrderBaseProps<TData> {
    /**
     * Ordered set of row ids.
     */
    rowOrder?: string[];
    defaultRowOrder?: never;
}
/**
 * Uncontrolled props for row order.
 * @public
 */
export interface DataTableRowOrderUncontrolledProps<TData extends DataTableRowData> extends DataTableRowOrderBaseProps<TData> {
    /**
     * Ordered set of row ids.
     */
    defaultRowOrder?: string[];
    rowOrder?: never;
}
/**
 * Extension interface to extend the types from the tanstack table instance.
 * @internal
 */
export interface DataTableRowOrderInstance<TRow = unknown, TRowModel = unknown> {
    /**
     * Internal storage for the row model with the changed order.
     * @internal
     */
    _getRowOrderRowModel?: () => TRowModel;
    /**
     * Allows access to the row order model if available.
     */
    getRowOrderRowModel: () => TRowModel;
    /**
     * Allows access to the row model which comes before the row order model.
     */
    getPreRowOrderRowModel: () => TRowModel;
    /**
     * Sets or updates the `state.rowOrder` state.
     */
    setRowOrder: (updater: Updater<string[]>) => void;
    /**
     * Sets the currently dragged row's id and index.
     */
    setDraggingRowInfo: (draggingRowInfo: {
        id: string;
        index: number;
        row: TRow;
    } | undefined) => void;
}
/**
 * Extension interface for the table options.
 * @internal
 */
export interface DataTableRowOrderOptions<TTable = unknown, TRow = unknown, TRowModel = unknown> {
    /**
     * Enables or disables row ordering.
     */
    enableRowOrdering?: boolean;
    /**
     * Callback function fired when row order has changed.
     * @param rowOrder - new order of rows. Contains IDs of the rows.
     */
    onRowOrderChange?: (rowOrder: string[]) => void;
    /**
     * RowModel option for the row order model.
     */
    getRowOrderRowModel?: (table: TTable) => () => TRowModel;
    /**
     * - Enables drag and drop row ordering for all rows in the table OR
     * - A function that given a row, returns whether to enable/disable the drag and drop handle for that row
     */
    enableRowOrderDragAndDrop?: boolean | ((row: TRow) => boolean);
    /**
     * Locks rows with disabled drag and drop in place if they are sorted to the start or end of the table.
     */
    lockDisabledRows?: boolean | 'start' | 'end';
}
/**
 * Extension interface to extend the types of the `Row` from the tanstack table.
 * @internal
 */
export interface DataTableRowOrderRow {
    /**
     *  Returns whether the row is draggable.
     */
    getCanDrag: () => boolean;
    /**
     * Flag determining if the row should be locked in place if drag and drop is disabled
     * and the row is sorted to the start or end of the table.
     */
    disabledRowDragAndDropLockPosition: boolean | 'start' | 'end';
}
/** @internal */
export interface DataTableRowOrderState<TRow = unknown> {
    /** Order of rows. */
    rowOrder: string[];
    draggingRowInfo: {
        id: string;
        index: number;
        row: TRow;
    } | undefined;
}
